27	namespace uhd { namespace transport { namespace sph {
28	
29	/***********************************************************************
30	 * Super send packet handler
31	 *
32	 * A send packet handler represents a group of channels.
33	 * The channel group shares a common sample rate.
34	 * All channels are sent in unison in send().
35	 **********************************************************************/
36	class send_packet_handler
37	{
38	public:
39	    typedef std::function<managed_send_buffer::sptr(double)> get_buff_type;
40	    typedef std::function<void(void)> post_send_cb_type;
41	    typedef std::function<bool(uhd::async_metadata_t&, const double)> async_receiver_type;
42	    typedef void (*vrt_packer_type)(uint32_t*, vrt::if_packet_info_t&);
43	    // typedef std::function<void(uint32_t *, vrt::if_packet_info_t &)> vrt_packer_type;
44	
45	    /*!
46	     * Make a new packet handler for send
47	     * \param size the number of transport channels
48	     */
49	    send_packet_handler(const size_t size = 1)
50	        : _next_packet_seq(0), _cached_metadata(false)
51	    {
52	        this->set_enable_trailer(true);
53	        this->resize(size);
54	    }
55	
56	    ~send_packet_handler(void)
57	    {
58	        /* NOP */
59	    }
60	
61	    //! Resize the number of transport channels
62	    void resize(const size_t size)
63	    {
64	        if (this->size() == size)
65	            return;
66	        _props.resize(size);
67	        static const uint64_t zero = 0;
68	        _zero_buffs.resize(size, &zero);
69	    }
70	
71	    //! Get the channel width of this handler
72	    size_t size(void) const
73	    {
74	        return _props.size();
75	    }
76	
77	    //! Setup the vrt packer function and offset
78	    void set_vrt_packer(
79	        const vrt_packer_type& vrt_packer, const size_t header_offset_words32 = 0)
80	    {
81	        _vrt_packer            = vrt_packer;
82	        _header_offset_words32 = header_offset_words32;
83	    }
84	
85	    //! Set the stream ID for a specific channel (or no SID)
86	    void set_xport_chan_sid(
87	        const size_t xport_chan, const bool has_sid, const uint32_t sid = 0)
88	    {
89	        _props.at(xport_chan).has_sid = has_sid;
90	        _props.at(xport_chan).sid     = sid;
91	    }
92	
93	    void set_enable_trailer(const bool enable)
94	    {
95	        _has_tlr = enable;
96	    }
97	
98	    //! Set the rate of ticks per second
99	    void set_tick_rate(const double rate)
100	    {
101	        _tick_rate = rate;
102	    }
103	
104	    //! Set the rate of samples per second
105	    void set_samp_rate(const double rate)
106	    {
107	        _samp_rate = rate;
108	    }
109	
110	    /*!
111	     * Set the function to get a managed buffer.
112	     * \param xport_chan which transport channel
113	     * \param get_buff the getter function
114	     */
115	    void set_xport_chan_get_buff(const size_t xport_chan, const get_buff_type& get_buff)
116	    {
117	        _props.at(xport_chan).get_buff = get_buff;
118	    }
119	
120	    /*!
121	     * Set the callback function for post-send.
122	     * \param xport_chan which transport channel
123	     * \param cb post-send callback
124	     */
125	    void set_xport_chan_post_send_cb(const size_t xport_chan, const post_send_cb_type& cb)
126	    {
127	        _props.at(xport_chan).go_postal = cb;
128	    }
129	
130	    //! Set the conversion routine for all channels
131	    void set_converter(const uhd::convert::id_type& id)
132	    {
133	        _num_inputs = id.num_inputs;
134	        _converter  = uhd::convert::get_converter(id)();
135	        this->set_scale_factor(32767.); // update after setting converter
136	        _bytes_per_otw_item = uhd::convert::get_bytes_per_item(id.output_format);
137	        _bytes_per_cpu_item = uhd::convert::get_bytes_per_item(id.input_format);
138	    }
139	
140	    /*!
141	     * Set the maximum number of samples per host packet.
142	     * Ex: A USRP1 in dual channel mode would be half.
143	     * \param num_samps the maximum samples in a packet
144	     */
145	    void set_max_samples_per_packet(const size_t num_samps)
146	    {
147	        _max_samples_per_packet = num_samps;
148	    }
149	
150	    //! Set the scale factor used in float conversion
151	    void set_scale_factor(const double scale_factor)
152	    {
153	        _converter->set_scalar(scale_factor);
154	    }
155	
156	    //! Set the callback to get async messages
157	    void set_async_receiver(const async_receiver_type& async_receiver)
158	    {
159	        _async_receiver = async_receiver;
160	    }
161	
162	    //! Overload call to get async metadata
163	    bool recv_async_msg(uhd::async_metadata_t& async_metadata, double timeout = 0.1)
164	    {
165	        if (_async_receiver)
166	            return _async_receiver(async_metadata, timeout);
167	        std::this_thread::sleep_for(std::chrono::microseconds(long(timeout * 1e6)));
168	        return false;
169	    }
170	
171	    /*******************************************************************
172	     * Send:
173	     * The entry point for the fast-path send calls.
174	     * Dispatch into combinations of single packet send calls.
175	     ******************************************************************/
176	    UHD_INLINE size_t send(const uhd::tx_streamer::buffs_type& buffs,
177	        const size_t nsamps_per_buff,
178	        const uhd::tx_metadata_t& metadata,
179	        const double timeout)
180	    {
181	        // translate the metadata to vrt if packet info
182	        vrt::if_packet_info_t if_packet_info;
183	        if_packet_info.packet_type = vrt::if_packet_info_t::PACKET_TYPE_DATA;
184	        // if_packet_info.has_sid = false; //set per channel
185	        if_packet_info.has_cid = false;
186	        if_packet_info.has_tlr = _has_tlr;
187	        if_packet_info.has_tsi = false;
188	        if_packet_info.has_tsf = metadata.has_time_spec;
189	        if_packet_info.tsf     = metadata.time_spec.to_ticks(_tick_rate);
190	        if_packet_info.sob     = metadata.start_of_burst;
191	        if_packet_info.eob     = metadata.end_of_burst;
192	        if_packet_info.fc_ack  = false; // This is a data packet
193	
194	        /*
195	         * Metadata is cached when we get a send requesting a start of burst with no
196	         * samples. It is applied here on the next call to send() that actually has
197	         * samples to send.
198	         */
199	        if (_cached_metadata && nsamps_per_buff != 0) {
200	            // If the new metada has a time_spec, do not use the cached time_spec.
201	            if (!metadata.has_time_spec) {
202	                if_packet_info.has_tsf = _metadata_cache.has_time_spec;
203	                if_packet_info.tsf     = _metadata_cache.time_spec.to_ticks(_tick_rate);
204	            }
205	            if_packet_info.sob = _metadata_cache.start_of_burst;
206	            if_packet_info.eob = _metadata_cache.end_of_burst;
207	            _cached_metadata   = false;
208	        }
209	
210	        if (nsamps_per_buff <= _max_samples_per_packet) {
211	// TODO remove this code when sample counts of zero are supported by hardware
212	#ifndef SSPH_DONT_PAD_TO_ONE
213	            static const uint64_t zero = 0;
214	            _zero_buffs.resize(buffs.size(), &zero);
215	
216	            if (nsamps_per_buff == 0) {
217	                // if this is a start of a burst and there are no samples
218	                if (metadata.start_of_burst) {
219	                    // cache metadata and apply on the next send()
220	                    _metadata_cache  = metadata;
221	                    _cached_metadata = true;
222	                    return 0;
223	                } else {
224	                    // send requests with no samples are handled here (such as end of
225	                    // burst)
226	                    return send_one_packet(_zero_buffs, 1, if_packet_info, timeout) & 0x0;
227	                }
228	            }
229	#endif
230	
231	            size_t nsamps_sent =
232	                send_one_packet(buffs, nsamps_per_buff, if_packet_info, timeout);
233	            return nsamps_sent;
234	        }
235	        size_t total_num_samps_sent = 0;
236	
237	        // false until final fragment
238	        if_packet_info.eob = false;
239	
240	        const size_t num_fragments = (nsamps_per_buff - 1) / _max_samples_per_packet;
241	        const size_t final_length = ((nsamps_per_buff - 1) % _max_samples_per_packet) + 1;
242	
243	        // loop through the following fragment indexes
244	        for (size_t i = 0; i < num_fragments; i++) {
245	            // send a fragment with the helper function
246	            const size_t num_samps_sent = send_one_packet(buffs,
247	                _max_samples_per_packet,
248	                if_packet_info,
249	                timeout,
250	                total_num_samps_sent * _bytes_per_cpu_item);
251	            total_num_samps_sent += num_samps_sent;
252	            if (num_samps_sent == 0)
253	                return total_num_samps_sent;
254	
255	            // setup metadata for the next fragment
256	            const time_spec_t time_spec =
257	                metadata.time_spec
258	                + time_spec_t::from_ticks(total_num_samps_sent, _samp_rate);
259	            if_packet_info.tsf = time_spec.to_ticks(_tick_rate);
260	            if_packet_info.sob = false;
261	        }
262	
263	        // send the final fragment with the helper function
264	        if_packet_info.eob = metadata.end_of_burst;
265	        size_t nsamps_sent = total_num_samps_sent
266	                             + send_one_packet(buffs,
267	                                 final_length,
268	                                 if_packet_info,
269	                                 timeout,
270	                                 total_num_samps_sent * _bytes_per_cpu_item);
271	        return nsamps_sent;
272	    }
273	
274	private:
275	    vrt_packer_type _vrt_packer;
276	    size_t _header_offset_words32;
277	    double _tick_rate, _samp_rate;
278	    struct xport_chan_props_type
279	    {
280	        xport_chan_props_type(void) : has_sid(false), sid(0) {}
281	        get_buff_type get_buff;
282	        post_send_cb_type go_postal;
283	        bool has_sid;
284	        uint32_t sid;
285	        managed_send_buffer::sptr buff;
286	    };
287	    std::vector<xport_chan_props_type> _props;
288	    size_t _num_inputs;
289	    size_t _bytes_per_otw_item; // used in conversion
290	    size_t _bytes_per_cpu_item; // used in conversion
291	    uhd::convert::converter::sptr _converter; // used in conversion
292	    size_t _max_samples_per_packet;
293	    std::vector<const void*> _zero_buffs;
294	    size_t _next_packet_seq;
295	    bool _has_tlr;
296	    async_receiver_type _async_receiver;
297	    bool _cached_metadata;
298	    uhd::tx_metadata_t _metadata_cache;
299	
300	
301	    /*******************************************************************
302	     * Send a single packet:
303	     ******************************************************************/
304	    UHD_INLINE size_t send_one_packet(const uhd::tx_streamer::buffs_type& buffs,
305	        const size_t nsamps_per_buff,
306	        vrt::if_packet_info_t& if_packet_info,
307	        const double timeout,
308	        const size_t buffer_offset_bytes = 0)
309	    {
310	        // load the rest of the if_packet_info in here
311	        if_packet_info.num_payload_bytes =
312	            nsamps_per_buff * _num_inputs * _bytes_per_otw_item;
313	        if_packet_info.num_payload_words32 =
314	            (if_packet_info.num_payload_bytes + 3 /*round up*/) / sizeof(uint32_t);
315	        if_packet_info.packet_count = _next_packet_seq;
316	
317	        // get a buffer for each channel or timeout
318	        for (xport_chan_props_type& props : _props) {
319	            if (not props.buff)
320	                props.buff = props.get_buff(timeout);
321	            if (not props.buff)
322	                return 0; // timeout
323	        }
324	
325	        // setup the data to share with converter threads
326	        _convert_nsamps              = nsamps_per_buff;
327	        _convert_buffs               = &buffs;
328	        _convert_buffer_offset_bytes = buffer_offset_bytes;
329	        _convert_if_packet_info      = &if_packet_info;
330	
331	        // perform N channels of conversion
332	        for (size_t i = 0; i < this->size(); i++) {
333	            convert_to_in_buff(i);
334	        }
335	
336	        _next_packet_seq++; // increment sequence after commits
337	        return nsamps_per_buff;
338	    }
339	
340	    /*! Run the conversion from the user's buffers to the internal buffer.
341	     *
342	     * - Calls the converter
343	     * - Releases internal data buffers
344	     * - Updates read/write pointers
345	     */
346	    UHD_INLINE void convert_to_in_buff(const size_t index)
347	    {
348	        // shortcut references to local data structures
349	        managed_send_buffer::sptr& buff      = _props[index].buff;
350	        vrt::if_packet_info_t if_packet_info = *_convert_if_packet_info;
351	        const tx_streamer::buffs_type& buffs = *_convert_buffs;
352	
353	        // fill IO buffs with pointers into the output buffer
354	        const void* io_buffs[4 /*max interleave*/];
355	        for (size_t i = 0; i < _num_inputs; i++) {
356	            const char* b = reinterpret_cast<const char*>(buffs[index * _num_inputs + i]);
357	            io_buffs[i]   = b + _convert_buffer_offset_bytes;
358	        }
359	        const ref_vector<const void*> in_buffs(io_buffs, _num_inputs);
360	
361	        // pack metadata into a vrt header
362	        uint32_t* otw_mem      = buff->cast<uint32_t*>() + _header_offset_words32;
363	        if_packet_info.has_sid = _props[index].has_sid;
364	        if_packet_info.sid     = _props[index].sid;
365	        _vrt_packer(otw_mem, if_packet_info);
366	        otw_mem += if_packet_info.num_header_words32;
367	
368	        // perform the conversion operation
369	        _converter->conv(in_buffs, otw_mem, _convert_nsamps);
370	
371	        // commit the samples to the zero-copy interface
372	        const size_t num_vita_words32 =
373	            _header_offset_words32 + if_packet_info.num_packet_words32;
374	        buff->commit(num_vita_words32 * sizeof(uint32_t));
375	        buff.reset(); // effectively a release
376	
377	        if (_props[index].go_postal) {
378	            _props[index].go_postal();
379	        }
380	    }
381	
382	    //! Shared variables for the worker threads
383	    size_t _convert_nsamps;
384	    const tx_streamer::buffs_type* _convert_buffs;
385	    size_t _convert_buffer_offset_bytes;
386	    vrt::if_packet_info_t* _convert_if_packet_info;
387	};
388	
389	class send_packet_streamer : public send_packet_handler, public tx_streamer
390	{
391	public:
392	    send_packet_streamer(const size_t max_num_samps)
393	    {
394	        _max_num_samps = max_num_samps;
395	        this->set_max_samples_per_packet(_max_num_samps);
396	    }
397	
398	    size_t get_num_channels(void) const override
399	    {
400	        return this->size();
401	    }
402	
403	    size_t get_max_num_samps(void) const override
404	    {
405	        return _max_num_samps;
406	    }
407	
408	    size_t send(const tx_streamer::buffs_type& buffs,
409	        const size_t nsamps_per_buff,
410	        const uhd::tx_metadata_t& metadata,
411	        const double timeout) override
412	    {
413	        return send_packet_handler::send(buffs, nsamps_per_buff, metadata, timeout);
414	    }
415	
416	    bool recv_async_msg(
417	        uhd::async_metadata_t& async_metadata, double timeout = 0.1) override
418	    {
419	        return send_packet_handler::recv_async_msg(async_metadata, timeout);
420	    }
421	    // Post an action to the output edge
422	    void post_output_action(
423	        const std::shared_ptr<uhd::rfnoc::action_info>&, const size_t) override
424	    {
425	        throw uhd::not_implemented_error("post_output_action is not implemented here!");
426	    }
427	
428	private:
429	    size_t _max_num_samps;
430	};
431	
432	}}} // namespace uhd::transport::sph
