9	"""
10	The vrt packer/unpacker code generator:
11	
12	This script will generate the pack and unpack routines that convert
13	metatdata into vrt headers and vrt headers into metadata.
14	
15	The generated code infers jump tables to speed-up the parsing time.
16	"""
17	
18	TMPL_TEXT = """<% import time %>
19	/***********************************************************************
20	 * This file was generated by ${file} on ${time.strftime("%c")}
21	 **********************************************************************/
22	
23	#include <uhd/exception.hpp>
24	#include <uhd/transport/vrt_if_packet.hpp>
25	#include <uhd/utils/byteswap.hpp>
26	#include <uhd/types/endianness.hpp>
27	#include <vector>
28	
29	//define the endian macros to convert integers
30	#ifdef UHD_BIG_ENDIAN
31	    #define BE_MACRO(x) (x)
32	    #define LE_MACRO(x) uhd::byteswap(x)
33	#else
34	    #define BE_MACRO(x) uhd::byteswap(x)
35	    #define LE_MACRO(x) (x)
36	#endif
37	
38	using namespace uhd;
39	using namespace uhd::transport;
40	using namespace uhd::transport::vrt;
41	
42	typedef size_t pred_type;
43	typedef std::vector<pred_type> pred_table_type;
44	#define pred_table_index(hdr) ((hdr >> 20) & 0x1ff)
45	
46	static pred_table_type get_pred_unpack_table(void)
47	{
48	    pred_table_type table(1 << 9, 0); //only 9 bits useful here (20-28)
49	    for (size_t i = 0; i < table.size(); i++){
50	        uint32_t vrt_hdr_word = i << 20;
51	        if(vrt_hdr_word & ${hex(0x1 << 28)}) table[i] |= ${hex(sid_p)};
52	        if(vrt_hdr_word & ${hex(0x1 << 27)}) table[i] |= ${hex(cid_p)};
53	        if(vrt_hdr_word & ${hex(0x3 << 22)}) table[i] |= ${hex(tsi_p)};
54	        if(vrt_hdr_word & ${hex(0x3 << 20)}) table[i] |= ${hex(tsf_p)};
55	        if(vrt_hdr_word & ${hex(0x1 << 26)}) table[i] |= ${hex(tlr_p)};
56	        if(vrt_hdr_word & ${hex(0x1 << 24)}) table[i] |= ${hex(eob_p)};
57	        if(vrt_hdr_word & ${hex(0x1 << 25)}) table[i] |= ${hex(sob_p)};
58	    }
59	    return table;
60	}
61	
62	static const pred_table_type pred_unpack_table(get_pred_unpack_table());
63	
64	//maps trailer bits to num empty bytes
65	//maps num empty bytes to trailer bits
66	static const uint32_t occ_table[] = {0, 2, 1, 3};
67	
68	const uint32_t VRLP = ('V' << 24) | ('R' << 16) | ('L' << 8) | ('P' << 0);
69	const uint32_t VEND = ('V' << 24) | ('E' << 16) | ('N' << 8) | ('D' << 0);
70	
71	UHD_INLINE static uint32_t chdr_to_vrt(const uint32_t chdr, if_packet_info_t &info)
72	{
73	    const uint32_t bytes = chdr & 0xffff;
74	    uint32_t vrt = (bytes + 3)/4;
75	    info.packet_count = (chdr >> 16) & 0xfff;
76	    vrt |= ((chdr >> 31) & 0x1) << 30; //context packet
77	    vrt |= ((chdr >> 29) & 0x1) << 20; //has tsf
78	    vrt |= ((chdr >> 28) & 0x1) << 24; //has eob
79	    vrt |= (0x1) << 28; //has sid (always)
80	    return vrt;
81	}
82	
83	UHD_INLINE static uint32_t vrt_to_chdr(const uint32_t vrt, const if_packet_info_t &info)
84	{
85	    const uint32_t words32 = vrt & 0xffff;
86	    int bytes_rem = info.num_payload_bytes % 4;
87	    if (bytes_rem != 0) bytes_rem -= 4; //adjust for round up
88	    uint32_t chdr = (words32 * 4) + bytes_rem;
89	    chdr |= (info.packet_count & 0xfff) << 16;
90	    chdr |= ((vrt >> 30) & 0x1) << 31; //context packet
91	    chdr |= ((vrt >> 20) & 0x1) << 29; //has tsf
92	    chdr |= ((vrt >> 24) & 0x1) << 28; //has eob
93	    return chdr;
94	}
95	
96	########################################################################
97	<%def name="gen_code(XE_MACRO, suffix)">
98	########################################################################
99	/***********************************************************************
100	 * internal impl of packing VRT IF header only
101	 **********************************************************************/
102	UHD_INLINE void __if_hdr_pack_${suffix}(
103	    uint32_t *packet_buff,
104	    if_packet_info_t &if_packet_info,
105	    uint32_t &vrt_hdr_word32
106	){
107	    uint32_t vrt_hdr_flags = 0;
108	
109	    pred_type pred = 0;
110	    if (if_packet_info.has_sid) pred |= ${hex(sid_p)};
111	    if (if_packet_info.has_cid) pred |= ${hex(cid_p)};
112	    if (if_packet_info.has_tsi) pred |= ${hex(tsi_p)};
113	    if (if_packet_info.has_tsf) pred |= ${hex(tsf_p)};
114	    if (if_packet_info.has_tlr) pred |= ${hex(tlr_p)};
115	    if (if_packet_info.eob)     pred |= ${hex(eob_p)};
116	    if (if_packet_info.sob)     pred |= ${hex(sob_p)};
117	
118	    switch(pred){
119	    % for pred in range(2**7):
120	    case ${pred}:<% num_header_words = 1 %><% flags = 0 %>
121	        ########## Stream ID ##########
122	        % if pred & sid_p:
123	            packet_buff[${num_header_words}] = ${XE_MACRO}(if_packet_info.sid);<% num_header_words += 1 %><% flags |= (0x1 << 28) %>
124	        % endif
125	        ########## Class ID ##########
126	        % if pred & cid_p:
127	            packet_buff[${num_header_words}] = 0; //not implemented<% num_header_words += 1 %>
128	            packet_buff[${num_header_words}] = 0; //not implemented<% num_header_words += 1 %><% flags |= (0x1 << 27) %>
129	        % endif
130	        ########## Integer Time ##########
131	        % if pred & tsi_p:
132	            packet_buff[${num_header_words}] = ${XE_MACRO}(if_packet_info.tsi);<% num_header_words += 1 %><% flags |= (0x3 << 22) %>
133	        % endif
134	        ########## Fractional Time ##########
135	        % if pred & tsf_p:
136	            packet_buff[${num_header_words}] = ${XE_MACRO}(uint32_t(if_packet_info.tsf >> 32));<% num_header_words += 1 %>
137	            packet_buff[${num_header_words}] = ${XE_MACRO}(uint32_t(if_packet_info.tsf >> 0));<% num_header_words += 1 %><% flags |= (0x1 << 20) %>
138	        % endif
139	        ########## Burst Flags ##########
140	<% if pred & eob_p: flags |= (0x1 << 24) %><% if pred & sob_p: flags |= (0x1 << 25) %>
141	        ########## Trailer ##########
142	        % if pred & tlr_p:
143	            {
144	                const size_t empty_bytes = if_packet_info.num_payload_words32*sizeof(uint32_t) - if_packet_info.num_payload_bytes;
145	                if_packet_info.tlr = (0x3 << 22) | (occ_table[empty_bytes & 0x3] << 10);
146	            }
147	            packet_buff[${num_header_words}+if_packet_info.num_payload_words32] = ${XE_MACRO}(if_packet_info.tlr);<% flags |= (0x1 << 26) %><% num_trailer_words = 1 %>
148	        % else:
149	<% num_trailer_words = 0 %>
150	        % endif
151	        ########## Variables ##########
152	            if_packet_info.num_header_words32 = ${num_header_words};
153	            if_packet_info.num_packet_words32 = ${num_header_words + num_trailer_words} + if_packet_info.num_payload_words32;
154	            vrt_hdr_flags = ${hex(flags)};
155	        break;
156	    % endfor
157	    }
