249	        if (metadata.error_code != rx_metadata_t::ERROR_CODE_NONE) {
250	            return accum_num_samps;
251	        }
252	
253	        // loop until buffer is filled or error code
254	        while (accum_num_samps < nsamps_per_buff) {
255	            size_t num_samps = recv_one_packet(buffs,
256	                nsamps_per_buff - accum_num_samps,
257	                _queue_metadata,
