393	    UHD_INLINE packet_type get_and_process_single_packet(const size_t index,
394	        per_buffer_info_type& prev_buffer_info,
395	        per_buffer_info_type& curr_buffer_info,
396	        double timeout)
397	    {
398	        managed_recv_buffer::sptr& buff = curr_buffer_info.buff;
399	        per_buffer_info_type& info      = curr_buffer_info;
400	        while (1) {
401	            // get a single packet from the transport layer
402	            buff = _props[index].get_buff(timeout);
403	            if (buff.get() == nullptr)
404	                return PACKET_TIMEOUT_ERROR;
405	
406	#ifdef ERROR_INJECT_DROPPED_PACKETS
407	            if (++recvd_packets > 1000) {
408	                recvd_packets = 0;
409	                buff.reset();
410	                buff = _props[index].get_buff(timeout);
411	                if (buff.get() == nullptr)
412	                    return PACKET_TIMEOUT_ERROR;
413	            }
414	#endif
415	
416	            // bounds check before extract
417	            const size_t num_packet_words32 = buff->size() / sizeof(uint32_t);
418	            if (num_packet_words32 <= _header_offset_words32) {
419	                throw std::runtime_error("recv buffer smaller than vrt packet offset");
420	            }
421	
422	            // extract packet info
423	            info.ifpi                    = {};
424	            info.ifpi.num_packet_words32 = num_packet_words32 - _header_offset_words32;
425	            info.vrt_hdr = buff->cast<const uint32_t*>() + _header_offset_words32;
426	            _vrt_unpacker(info.vrt_hdr, info.ifpi);
427	            info.time      = info.ifpi.tsf; // assumes has_tsf is true
428	            info.copy_buff = reinterpret_cast<const char*>(
429	                info.vrt_hdr + info.ifpi.num_header_words32);
430	
431	            // handle flow control
432	            if (_props[index].handle_flowctrl) {
433	                if ((info.ifpi.packet_count % _props[index].fc_update_window) == 0) {
434	                    _props[index].handle_flowctrl(info.ifpi.packet_count);
435	                }
436	            }
437	
438	            // handle flow control ack
439	            if (info.ifpi.fc_ack) {
440	                if (_props[index].handle_flowctrl_ack) {
441	                    _props[index].handle_flowctrl_ack(
442	                        reinterpret_cast<const uint32_t*>(info.copy_buff));
443	                }
444	                // Process the next packet
445	                buff.reset();
446	                info.copy_buff = nullptr;
447	                continue;
448	            }
449	
450	            break;
451	        }
452	
453	        //--------------------------------------------------------------
454	        //-- Determine return conditions:
455	        //-- The order of these checks is HOLY.
456	        //--------------------------------------------------------------
457	
458	        // 1) check for inline IF message packets
459	        if (info.ifpi.packet_type != vrt::if_packet_info_t::PACKET_TYPE_DATA) {
460	            return PACKET_INLINE_MESSAGE;
461	        }
462	
463	// 2) check for sequence errors
464	#ifndef SRPH_DONT_CHECK_SEQUENCE
465	        const size_t seq_mask =
466	            (info.ifpi.link_type == vrt::if_packet_info_t::LINK_TYPE_NONE) ? 0xf : 0xfff;
467	        const size_t expected_packet_count = _props[index].packet_count;
468	        _props[index].packet_count         = (info.ifpi.packet_count + 1) & seq_mask;
469	        if (expected_packet_count != info.ifpi.packet_count) {
470	            // UHD_LOGGER_INFO("STREAMER") << "expected: " << expected_packet_count << "
471	            // got: " << info.ifpi.packet_count;
472	            if (_props[index].handle_flowctrl) {
473	                // Always update flow control in this case, because we don't
474	                // know which packet was dropped and what state the upstream
475	                // flow control is in.
476	                _props[index].handle_flowctrl(info.ifpi.packet_count);
477	            }
478	            return PACKET_SEQUENCE_ERROR;
479	        }
480	#endif
481	
482	        // 3) check for out of order timestamps
483	        if (info.ifpi.has_tsf and prev_buffer_info.time > info.time) {
484	            return PACKET_TIMESTAMP_ERROR;
485	        }
486	
487	        // 4) otherwise the packet is normal!
488	        return PACKET_IF_DATA;
489	    }
