491	    void _flush_all(double timeout)
492	    {
493	        get_prev_buffer_info().reset();
494	        get_curr_buffer_info().reset();
495	        get_next_buffer_info().reset();
496	
497	        for (size_t i = 0; i < _props.size(); i++) {
498	            per_buffer_info_type prev_buffer_info, curr_buffer_info;
499	            prev_buffer_info.reset();
500	            curr_buffer_info.reset();
501	            while (true) {
502	                // receive a single packet from the transport
503	                try {
504	                    // call into get_and_process_single_packet()
505	                    // to make sure flow control is handled
506	                    if (get_and_process_single_packet(
507	                            i, prev_buffer_info, curr_buffer_info, timeout)
508	                        == PACKET_TIMEOUT_ERROR)
509	                        break;
510	                } catch (...) {
511	                }
512	                curr_buffer_info.buff.reset(); // Let my buffer go!
513	                prev_buffer_info = curr_buffer_info;
514	                curr_buffer_info.reset();
515	            }
516	        }
517	    }
