520	     * Alignment check:
521	     * Check the received packet for alignment and mark accordingly.
522	     ******************************************************************/
523	    UHD_INLINE void alignment_check(const size_t index, buffers_info_type& info)
524	    {
525	        // if alignment time was not valid or if the sequence id is newer:
526	        //  use this index's time as the alignment time
527	        //  reset the indexes list and remove this index
528	        if (not info.alignment_time_valid or info[index].time > info.alignment_time) {
529	            info.alignment_time_valid = true;
530	            info.alignment_time       = info[index].time;
531	            info.indexes_todo.set();
532	            info.indexes_todo.reset(index);
533	            // release the other buffers
534	            for (size_t i = 0; i < info.size(); i++) {
535	                if (i != index) {
536	                    info[i].reset();
537	                }
538	            }
539	            info.data_bytes_to_copy = info[index].ifpi.num_payload_bytes;
540	            // reset start_of_burst and end_of_burst states
541	            info.metadata.start_of_burst = info[index].ifpi.sob;
542	            info.metadata.end_of_burst   = info[index].ifpi.eob;
543	        }
544	
545	        // if the sequence id matches:
546	        //  remove this index from the list and continue
547	        else if (info[index].time == info.alignment_time) {
548	            info.indexes_todo.reset(index);
549	            // All channels should have sob set at the same time, so only
550	            // set start_of burst if all channels have sob set.
551	            info.metadata.start_of_burst &= info[index].ifpi.sob;
552	            // If any channel indicates eob, no more data will be received for
553	            // that channel so set end_of_burst for any eob.
554	            info.metadata.end_of_burst |= info[index].ifpi.eob;
555	        } else {
556	            // Not going to use this buffer, so release it
557	            info[index].reset();
558	        }
559	
560	        // if the sequence id is older:
561	        //  continue with the same index to try again
562	        // else if (info[index].time < info.alignment_time)...
563	    }
564	
565	    /*******************************************************************
566	     * Get aligned buffers:
567	     * Iterate through each index and try to accumulate aligned buffers.
568	     * Handle all of the edge cases like inline messages and errors.
569	     * The logic will throw out older packets until it finds a match.
570	     ******************************************************************/
571	    UHD_INLINE void get_aligned_buffs(double timeout)
572	    {
573	        get_prev_buffer_info()
574	            .reset(); // no longer need the previous info - reset it for future use
575	
576	        increment_buffer_info(); // increment to next buffer
577	
578	        buffers_info_type& prev_info = get_prev_buffer_info();
579	        buffers_info_type& curr_info = get_curr_buffer_info();
580	        buffers_info_type& next_info = get_next_buffer_info();
581	
582	        curr_info.metadata.error_code = rx_metadata_t::ERROR_CODE_NONE;
583	
584	        // Loop until we get a message of an aligned set of buffers:
585	        // - Receive a single packet and extract its info.
586	        // - Handle the packet type yielded by the receive.
587	        // - Check the timestamps for alignment conditions.
588	        size_t iterations = 0;
589	        while (curr_info.indexes_todo.any()) {
590	            // get the index to process for this iteration
591	            const size_t index = curr_info.indexes_todo.find_first();
592	            packet_type packet;
593	
594	            // receive a single packet from the transport
595	            try {
596	                packet = get_and_process_single_packet(
597	                    index, prev_info[index], curr_info[index], timeout);
598	            }
599	
600	            // handle the case where a bad header exists
601	            catch (const uhd::value_error& e) {
602	                UHD_LOGGER_ERROR("STREAMER")
603	                    << boost::format(
604	                           "The receive packet handler caught a value exception.\n%s")
605	                           % e.what();
606	                std::swap(curr_info, next_info); // save progress from curr -> next
607	                curr_info.metadata.error_code = rx_metadata_t::ERROR_CODE_BAD_PACKET;
608	                return;
609	            }
610	
611	            switch (packet) {
612	                case PACKET_IF_DATA:
613	                    alignment_check(index, curr_info);
614	                    break;
615	
616	                case PACKET_TIMESTAMP_ERROR:
617	                    // If the user changes the device time while streaming or without
618	                    // flushing, we can receive a packet that comes before the previous
619	                    // packet in time. This could cause the alignment logic to discard
620	                    // future received packets. Therefore, when this occurs, we reset the
621	                    // info to restart from scratch.
622	                    if (curr_info.alignment_time_valid
623	                        and curr_info.alignment_time != curr_info[index].time) {
624	                        curr_info.alignment_time_valid = false;
625	                    }
626	                    alignment_check(index, curr_info);
627	                    break;
628	
629	                case PACKET_INLINE_MESSAGE:
630	                    std::swap(curr_info, next_info); // save progress from curr -> next
631	                    curr_info.metadata.has_time_spec = next_info[index].ifpi.has_tsf;
632	                    curr_info.metadata.time_spec =
633	                        time_spec_t::from_ticks(next_info[index].time, _tick_rate);
634	                    curr_info.metadata.error_code =
635	                        rx_metadata_t::error_code_t(get_context_code(
636	                            next_info[index].vrt_hdr, next_info[index].ifpi));
637	                    if (curr_info.metadata.error_code
638	                        == rx_metadata_t::ERROR_CODE_OVERFLOW) {
639	                        // Not sending flow control would cause timeouts due to source
640	                        // flow control locking up. Send first as the overrun handler may
641	                        // flush the receive buffers which could contain packets with
642	                        // sequence numbers after this packet's sequence number!
643	                        if (_props[index].handle_flowctrl) {
644	                            _props[index].handle_flowctrl(
645	                                next_info[index].ifpi.packet_count);
646	                        }
647	
648	                        rx_metadata_t metadata = curr_info.metadata;
649	                        _props[index].handle_overflow();
650	                        curr_info.metadata = metadata;
651	                        UHD_LOG_FASTPATH("O");
652	                    }
653	                    next_info[index].buff.reset(); // No data, so release the buffer
654	                    next_info[index].copy_buff = nullptr;
655	
656	                    return;
657	
658	                case PACKET_TIMEOUT_ERROR:
659	                    std::swap(curr_info, next_info); // save progress from curr -> next
660	                    if (_props[index].handle_flowctrl) {
661	                        _props[index].handle_flowctrl(next_info[index].ifpi.packet_count);
662	                    }
663	                    curr_info.metadata.error_code = rx_metadata_t::ERROR_CODE_TIMEOUT;
664	                    return;
665	
666	                case PACKET_SEQUENCE_ERROR:
667	                    alignment_check(index, curr_info);
668	                    std::swap(curr_info, next_info); // save progress from curr -> next
669	                    curr_info.metadata.has_time_spec = prev_info.metadata.has_time_spec;
670	                    curr_info.metadata.time_spec =
671	                        prev_info.metadata.time_spec
672	                        + time_spec_t::from_ticks(
673	                            prev_info[index].ifpi.num_payload_words32 * sizeof(uint32_t)
674	                                / _bytes_per_otw_item,
675	                            _samp_rate);
676	                    curr_info.metadata.out_of_sequence = true;
677	                    curr_info.metadata.error_code = rx_metadata_t::ERROR_CODE_OVERFLOW;
678	                    UHD_LOG_FASTPATH("D");
679	                    return;
680	            }
681	
682	            // too many iterations: detect alignment failure
683	            if (iterations++ > _alignment_failure_threshold) {
684	                UHD_LOGGER_ERROR("STREAMER")
685	                    << boost::format(
686	                           "The receive packet handler failed to time-align packets.\n"
687	                           "%u received packets were processed by the handler.\n"
688	                           "However, a timestamp match could not be determined.\n")
689	                           % iterations
690	                    << std::endl;
691	                std::swap(curr_info, next_info); // save progress from curr -> next
692	                curr_info.metadata.error_code = rx_metadata_t::ERROR_CODE_ALIGNMENT;
693	                _props[index].handle_overflow();
694	                return;
695	            }
696	        }
697	
698	        // set the metadata from the buffer information at index zero
699	        curr_info.metadata.has_time_spec = curr_info[0].ifpi.has_tsf;
700	        curr_info.metadata.time_spec =
701	            time_spec_t::from_ticks(curr_info[0].time, _tick_rate);
702	        curr_info.metadata.more_fragments  = false;
703	        curr_info.metadata.fragment_offset = 0;
704	        curr_info.metadata.error_code      = rx_metadata_t::ERROR_CODE_NONE;
705	    }
706	
707	    /*******************************************************************
708	     * Receive a single packet on all channels
709	     * Handles fragmentation, messages, errors, and copy-conversion.
710	     * When no fragments are available, call the get aligned buffers.
711	     * Then copy-convert available data into the user's IO buffers.
712	     ******************************************************************/
713	    UHD_INLINE size_t recv_one_packet(const uhd::rx_streamer::buffs_type& buffs,
714	        const size_t nsamps_per_buff,
715	        uhd::rx_metadata_t& metadata,
716	        const double timeout,
717	        const size_t buffer_offset_bytes = 0)
718	    {
719	        // get the next buffer if the current one has expired
720	        if (get_curr_buffer_info().data_bytes_to_copy == 0) {
721	            // perform receive with alignment logic
722	            get_aligned_buffs(timeout);
723	        }
724	
725	        buffers_info_type& info = get_curr_buffer_info();
726	        metadata                = info.metadata;
727	
728	        // interpolate the time spec (useful when this is a fragment)
729	        metadata.time_spec +=
730	            time_spec_t::from_ticks(info.fragment_offset_in_samps, _samp_rate);
731	
732	        // extract the number of samples available to copy
733	        const size_t nsamps_available = info.data_bytes_to_copy / _bytes_per_otw_item;
734	        const size_t nsamps_to_copy =
735	            std::min(nsamps_per_buff * _num_outputs, nsamps_available);
736	        const size_t bytes_to_copy              = nsamps_to_copy * _bytes_per_otw_item;
737	        const size_t nsamps_to_copy_per_io_buff = nsamps_to_copy / _num_outputs;
738	
739	        // setup the data to share with converter threads
740	        _convert_nsamps              = nsamps_to_copy_per_io_buff;
741	        _convert_buffs               = &buffs;
742	        _convert_buffer_offset_bytes = buffer_offset_bytes;
743	        _convert_bytes_to_copy       = bytes_to_copy;
744	
745	        // perform N channels of conversion
746	        for (size_t i = 0; i < this->size(); i++) {
747	            convert_to_out_buff(i);
748	        }
749	
750	        // update the copy buffer's availability
751	        info.data_bytes_to_copy -= bytes_to_copy;
752	
753	        // setup the fragment flags and offset
754	        metadata.more_fragments  = info.data_bytes_to_copy != 0;
755	        metadata.fragment_offset = info.fragment_offset_in_samps;
756	        info.fragment_offset_in_samps += nsamps_to_copy; // set for next call
757	
758	        return nsamps_to_copy_per_io_buff;
759	    }
760	
761	    /*! Run the conversion from the internal buffers to the user's output
762	     *  buffer.
763	     *
764	     * - Calls the converter
765	     * - Releases internal data buffers
766	     * - Updates read/write pointers
767	     */
768	    inline void convert_to_out_buff(const size_t index)
769	    {
770	        // shortcut references to local data structures
771	        buffers_info_type& buff_info         = get_curr_buffer_info();
772	        per_buffer_info_type& info           = buff_info[index];
773	        const rx_streamer::buffs_type& buffs = *_convert_buffs;
774	
775	        // fill IO buffs with pointers into the output buffer
776	        void* io_buffs[4 /*max interleave*/];
777	        for (size_t i = 0; i < _num_outputs; i++) {
778	            char* b     = reinterpret_cast<char*>(buffs[index * _num_outputs + i]);
779	            io_buffs[i] = b + _convert_buffer_offset_bytes;
780	        }
781	        const ref_vector<void*> out_buffs(io_buffs, _num_outputs);
782	
783	        // perform the conversion operation
784	        _converter->conv(info.copy_buff, out_buffs, _convert_nsamps);
785	
786	        // advance the pointer for the source buffer
787	        info.copy_buff += _convert_bytes_to_copy;
788	
789	        // release the buffer if fully consumed
790	        if (buff_info.data_bytes_to_copy == _convert_bytes_to_copy) {
791	            info.buff.reset(); // effectively a release
792	        }
793	    }
794	
795	    //! Shared variables for the worker threads
796	    size_t _convert_nsamps;
797	    const rx_streamer::buffs_type* _convert_buffs;
798	    size_t _convert_buffer_offset_bytes;
799	    size_t _convert_bytes_to_copy;
800	};
801	
802	class recv_packet_streamer : public recv_packet_handler, public rx_streamer
803	{
804	public:
805	    recv_packet_streamer(const size_t max_num_samps)
806	    {
807	        _max_num_samps = max_num_samps;
808	    }
809	
810	    size_t get_num_channels(void) const override
811	    {
812	        return this->size();
813	    }
814	
815	    size_t get_max_num_samps(void) const override
816	    {
817	        return _max_num_samps;
818	    }
819	
820	    size_t recv(const rx_streamer::buffs_type& buffs,
821	        const size_t nsamps_per_buff,
822	        uhd::rx_metadata_t& metadata,
823	        const double timeout,
824	        const bool one_packet) override
825	    {
826	        return recv_packet_handler::recv(
827	            buffs, nsamps_per_buff, metadata, timeout, one_packet);
828	    }
829	
830	    void issue_stream_cmd(const stream_cmd_t& stream_cmd) override
831	    {
832	        return recv_packet_handler::issue_stream_cmd(stream_cmd);
833	    }
834	
835	    // Post an action to the input edge.
836	    void post_input_action(
837	        const std::shared_ptr<uhd::rfnoc::action_info>&, const size_t) override
838	    {
839	        throw uhd::not_implemented_error("post_input_action is not implemented here!");
840	    }
841	
842	private:
843	    size_t _max_num_samps;
844	};
845	
846	}}} // namespace uhd::transport::sph
847	
848	#endif /* INCLUDED_LIBUHD_TRANSPORT_SUPER_RECV_PACKET_HANDLER_HPP */
