8	#include <uhd/transport/vrt_if_packet.hpp>
9	#include <uhd/utils/byteswap.hpp>
10	#include <boost/format.hpp>
11	#include <boost/test/unit_test.hpp>
12	#include <cstdlib>
13	#include <iostream>
14	
15	using namespace uhd::transport;
16	
17	static void pack_and_unpack(vrt::if_packet_info_t& if_packet_info_in)
18	{
19	    if (if_packet_info_in.num_payload_bytes == 0) {
20	        if_packet_info_in.num_payload_bytes =
21	            if_packet_info_in.num_payload_words32 * sizeof(uint32_t);
22	    }
23	    uint32_t packet_buff[2048];
24	
25	    // pack metadata into a vrt header
26	    vrt::if_hdr_pack_be(packet_buff, if_packet_info_in);
27	    std::cout << std::endl;
28	    for (size_t i = 0; i < 5; i++) {
29	        std::cout << boost::format("packet_buff[%u] = 0x%.8x") % i
30	                         % uhd::byteswap(packet_buff[i])
31	                  << std::endl;
32	    }
33	
34	    vrt::if_packet_info_t if_packet_info_out;
35	    if_packet_info_out.link_type          = if_packet_info_in.link_type;
36	    if_packet_info_out.num_packet_words32 = if_packet_info_in.num_packet_words32;
37	
38	    // unpack the vrt header back into metadata
39	    vrt::if_hdr_unpack_be(packet_buff, if_packet_info_out);
40	
41	    // check the the unpacked metadata is the same
42	    BOOST_CHECK_EQUAL(if_packet_info_in.packet_count, if_packet_info_out.packet_count);
43	    BOOST_CHECK_EQUAL(
44	        if_packet_info_in.num_header_words32, if_packet_info_out.num_header_words32);
45	    BOOST_CHECK_EQUAL(
46	        if_packet_info_in.num_payload_words32, if_packet_info_out.num_payload_words32);
47	    BOOST_CHECK_EQUAL(if_packet_info_in.has_sid, if_packet_info_out.has_sid);
48	    if (if_packet_info_in.has_sid and if_packet_info_out.has_sid) {
49	        BOOST_CHECK_EQUAL(if_packet_info_in.sid, if_packet_info_out.sid);
50	    }
51	    BOOST_CHECK_EQUAL(if_packet_info_in.has_cid, if_packet_info_out.has_cid);
52	    if (if_packet_info_in.has_cid and if_packet_info_out.has_cid) {
53	        BOOST_CHECK_EQUAL(if_packet_info_in.cid, if_packet_info_out.cid);
54	    }
55	    BOOST_CHECK_EQUAL(if_packet_info_in.has_tsi, if_packet_info_out.has_tsi);
56	    if (if_packet_info_in.has_tsi and if_packet_info_out.has_tsi) {
57	        BOOST_CHECK_EQUAL(if_packet_info_in.tsi, if_packet_info_out.tsi);
58	    }
59	    BOOST_CHECK_EQUAL(if_packet_info_in.has_tsf, if_packet_info_out.has_tsf);
60	    if (if_packet_info_in.has_tsf and if_packet_info_out.has_tsf) {
61	        BOOST_CHECK_EQUAL(if_packet_info_in.tsf, if_packet_info_out.tsf);
62	    }
63	    BOOST_CHECK_EQUAL(if_packet_info_in.has_tlr, if_packet_info_out.has_tlr);
64	    if (if_packet_info_in.has_tlr and if_packet_info_out.has_tlr) {
65	        BOOST_CHECK_EQUAL(if_packet_info_in.tlr, if_packet_info_out.tlr);
66	    }
67	}
68	
69	/***********************************************************************
70	 * Loopback test the vrt packer/unpacker with various packet info combos
71	 * The trailer is not tested as it is not convenient to do so.
72	 **********************************************************************/
